    28→// Get skill catalog with user's assessment history
    29→router.get('/available', authMiddleware, async (req, res) => {
    30→  try {
    31→    const userId = req.user.id;
    32→
    33→    // Get user's existing skills and assessment data
    34→    const userSkillsResult = await pool.query(`
    35→      SELECT cs.id, cs.skill_name, cs.category, cs.level, cs.is_verified, cs.verified_score,
    36→             COUNT(sa.id) as assessment_count,
    37→             MAX(sa.score) as best_score,
    38→             MAX(sa.completed_at) as last_attempted
    39→      FROM candidate_skills cs
    40→      LEFT JOIN skill_assessments sa ON cs.id = sa.skill_id AND sa.completed_at IS NOT NULL
    41→      WHERE cs.user_id = $1
    42→      GROUP BY cs.id
    43→      ORDER BY cs.is_verified ASC, cs.created_at DESC
    44→    `, [userId]);
    45→
    46→    const userSkillMap = {};
    47→    for (const skill of userSkillsResult.rows) {
    48→      userSkillMap[skill.skill_name.toLowerCase()] = skill;
    49→    }
    50→
    51→    // Build catalog with user's data overlaid
    52→    const catalog = SKILL_CATALOG.map(catalogSkill => {
    53→      const userSkill = userSkillMap[catalogSkill.name.toLowerCase()];
    54→      return {
    55→        catalog_name: catalogSkill.name,
    56→        category: catalogSkill.category,
    57→        icon: catalogSkill.icon,
    58→        description: catalogSkill.description,
    59→        difficulty: catalogSkill.difficulty,
    60→        // User-specific data
    61→        skill_id: userSkill ? userSkill.id : null,
    62→        is_verified: userSkill ? userSkill.is_verified : false,
    63→        verified_score: userSkill ? userSkill.verified_score : null,
    64→        assessment_count: userSkill ? parseInt(userSkill.assessment_count) : 0,
    65→        best_score: userSkill ? userSkill.best_score : null,
    66→        last_attempted: userSkill ? userSkill.last_attempted : null,
    67→      };
    68→    });
    69→
    70→    // Also include any user skills NOT in the catalog
    71→    for (const skill of userSkillsResult.rows) {
    72→      const inCatalog = SKILL_CATALOG.some(c => c.name.toLowerCase() === skill.skill_name.toLowerCase());
    73→      if (!inCatalog) {
    74→        catalog.push({
    75→          catalog_name: skill.skill_name,
    76→          category: skill.category,
    77→          icon: skill.skill_name.substring(0, 2).toUpperCase(),
    78→          description: `Custom skill: ${skill.skill_name}`,
    79→          difficulty: 'Adaptive',
    80→          skill_id: skill.id,
    81→          is_verified: skill.is_verified,
    82→          verified_score: skill.verified_score,
    83→          assessment_count: parseInt(skill.assessment_count),
    84→          best_score: skill.best_score,
    85→          last_attempted: skill.last_attempted,
    86→        });
    87→      }
    88→    }
    89→
    90→    res.json({ skills: catalog });
    91→  } catch (error) {
    92→    console.error('Error fetching available assessments:', error);
    93→    res.status(500).json({ error: 'Failed to fetch assessments' });
    94→  }
    95→});
