   997→    const recruiterRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
   998→    if (!recruiterRoles.includes(req.user.role)) {
   999→      return res.status(403).json({ error: 'Recruiter access required' });
  1000→    }
  1001→
  1002→    const { jobId } = req.body;
  1003→    if (!jobId) return res.status(400).json({ error: 'jobId is required' });
  1004→
  1005→    // Get job details
  1006→    const jobResult = await pool.query('SELECT * FROM jobs WHERE id = $1', [jobId]);
  1007→    if (jobResult.rows.length === 0) {
  1008→      return res.status(404).json({ error: 'Job not found' });
  1009→    }
  1010→    const job = jobResult.rows[0];
  1011→
  1012→    // Check if assessment already exists for this job
  1013→    const existing = await pool.query(
  1014→      'SELECT id FROM job_assessments WHERE job_id = $1 AND status != $2',
  1015→      [jobId, 'archived']
  1016→    );
  1017→    if (existing.rows.length > 0) {
  1018→      return res.status(409).json({
  1019→        error: 'Assessment already exists for this job',
  1020→        assessmentId: existing.rows[0].id
  1021→      });
  1022→    }
  1023→
  1024→    // Detect job level from title/description for difficulty targeting
  1025→    const titleLower = (job.title || '').toLowerCase();
  1026→    const descLower = (job.description || '').toLowerCase();
  1027→    let targetLevel = 'mid';
  1028→    if (titleLower.includes('senior') || titleLower.includes('lead') || titleLower.includes('principal') || titleLower.includes('staff')) {
  1029→      targetLevel = 'senior';
  1030→    } else if (titleLower.includes('junior') || titleLower.includes('intern') || titleLower.includes('entry') || descLower.includes('0-2 years')) {
  1031→      targetLevel = 'junior';
  1032→    }
  1033→
  1034→    const difficultyRange = { junior: '1-2', mid: '2-3', senior: '3-5' }[targetLevel];
  1035→
  1036→    // Generate assessment questions via AI
  1037→    const prompt = `You are an expert hiring manager. Generate a comprehensive skill assessment for this job posting.
  1038→
  1039→JOB TITLE: ${job.title}
  1040→COMPANY: ${job.company || 'Not specified'}
  1041→DESCRIPTION: ${(job.description || '').substring(0, 2000)}
  1042→REQUIREMENTS: ${(job.requirements || '').substring(0, 1500)}
  1043→JOB TYPE: ${job.job_type || 'full-time'}
  1044→LEVEL: ${targetLevel}
  1045→
  1046→Generate exactly 15 assessment questions across these categories:
  1047→- "technical" (6 questions): Test specific technical skills mentioned in requirements
  1048→- "scenario" (4 questions): Real-world work scenarios relevant to the role
  1049→- "behavioral" (3 questions): Soft skills, teamwork, communication, problem-solving
  1050→- "code_challenge" (2 questions): Practical coding/analytical problems (if technical role) OR additional scenario questions (if non-technical)
  1051→
  1052→For each question, include:
  1053→- question_type: "multiple_choice", "free_text", "scenario_response", or "code_challenge"
