  1421→
  1422→    // Adaptive difficulty: adjust based on performance in category
  1423→    const categoryAnswers = answers.filter(a => a.category === question.category);
  1424→    const categoryCorrect = categoryAnswers.filter(a => a.quickScore > 0).length;
  1425→    const categoryRate = categoryAnswers.length > 0 ? categoryCorrect / categoryAnswers.length : 0.5;
  1426→    let newDifficulty = attempt.current_difficulty || 3;
