  1429→
  1430→    const newTimeAnomalies = (attempt.time_anomalies || 0) + (isTimeAnomaly ? 1 : 0);
  1431→    const newTimeSpent = (attempt.time_spent_seconds || 0) + (timeTaken || 0);
  1432→
  1433→    await client.query(`
  1434→      UPDATE job_assessment_attempts
