  1497→// Score an assessment attempt using AI
  1498→async function scoreAttempt(attemptId, assessmentId) {
  1499→  try {
  1500→    const attempt = await pool.query('SELECT * FROM job_assessment_attempts WHERE id = $1', [attemptId]);
  1501→    if (attempt.rows.length === 0) return;
  1502→    const att = attempt.rows[0];
  1503→
  1504→    const answers = typeof att.answers === 'string' ? JSON.parse(att.answers) : (att.answers || []);
  1505→    if (answers.length === 0) return;
  1506→
  1507→    // Get all questions
  1508→    const questions = await pool.query(
  1509→      'SELECT * FROM job_assessment_questions WHERE assessment_id = $1 ORDER BY order_index',
  1510→      [assessmentId]
  1511→    );
  1512→    const qMap = {};
  1513→    for (const q of questions.rows) qMap[q.id] = q;
  1514→
  1515→    // Group answers by category
  1516→    const categoryGroups = {};
  1517→    let totalPoints = 0;
  1518→    let earnedPoints = 0;
  1519→
  1520→    for (const ans of answers) {
  1521→      const q = qMap[ans.questionId];
  1522→      if (!q) continue;
  1523→
  1524→      if (!categoryGroups[q.category]) {
  1525→        categoryGroups[q.category] = { questions: [], totalPoints: 0, earnedPoints: 0 };
  1526→      }
  1527→
  1528→      totalPoints += q.points;
  1529→
  1530→      if (q.question_type === 'multiple_choice') {
  1531→        // Already scored
  1532→        const pts = ans.quickScore || 0;
  1533→        earnedPoints += pts;
  1534→        categoryGroups[q.category].earnedPoints += pts;
  1535→        categoryGroups[q.category].totalPoints += q.points;
  1536→        categoryGroups[q.category].questions.push({
  1537→          text: q.question_text, answer: ans.answer, score: pts, maxPoints: q.points, type: 'multiple_choice'
  1538→        });
  1539→      } else {
  1540→        // AI-score free text / scenario / code challenge
  1541→        const scorePrompt = `Score this assessment answer.
  1542→
  1543→QUESTION (${q.category}, ${q.question_type}): ${q.question_text}
  1544→${q.rubric ? 'RUBRIC: ' + q.rubric : ''}
  1545→${q.correct_answer ? 'EXPECTED: ' + q.correct_answer : ''}
  1546→MAX POINTS: ${q.points}
  1547→
  1548→CANDIDATE'S ANSWER: ${ans.answer}
  1549→
  1550→Score on three dimensions:
  1551→- Relevance: Does it address the question? (0-100)
  1552→- Depth: How thorough and insightful? (0-100)
  1553→- Accuracy: Is the information correct? (0-100)
  1554→
  1555→Return ONLY valid JSON:
  1556→{
  1557→  "relevance": 0-100,
  1558→  "depth": 0-100,
  1559→  "accuracy": 0-100,
  1560→  "score": 0-${q.points},
  1561→  "feedback": "2-3 sentence explanation of the score",
  1562→  "strengths": ["strength 1"],
  1563→  "weaknesses": ["weakness 1"]
  1564→}`;
  1565→
  1566→        try {
  1567→          const scoreResponse = await chat(scorePrompt, {
  1568→            maxTokens: 512,
  1569→            module: 'assessments', feature: 'ai_scoring'
  1570→          });
  1571→          const scoreData = safeParseJSON(scoreResponse);
  1572→          if (scoreData) {
  1573→            const pts = Math.min(q.points, Math.max(0, scoreData.score || 0));
  1574→            earnedPoints += pts;
  1575→            categoryGroups[q.category].earnedPoints += pts;
  1576→            categoryGroups[q.category].totalPoints += q.points;
