  1777→// Conversational assessment — AI asks follow-up questions based on answers
  1778→router.post('/job-assessment/:id/converse', authMiddleware, async (req, res) => {
  1779→  try {
  1780→    const assessmentId = req.params.id;
  1781→    const candidateId = req.user.id;
  1782→    const { attemptId, questionId, message } = req.body;
  1783→
  1784→    if (!attemptId || !message) {
  1785→      return res.status(400).json({ error: 'attemptId and message required' });
  1786→    }
  1787→
  1788→    // Get the question context
  1789→    const qResult = await pool.query(
  1790→      'SELECT * FROM job_assessment_questions WHERE id = $1 AND assessment_id = $2',
  1791→      [questionId, assessmentId]
  1792→    );
  1793→    if (qResult.rows.length === 0) {
  1794→      return res.status(404).json({ error: 'Question not found' });
  1795→    }
  1796→    const question = qResult.rows[0];
  1797→
  1798→    // Get conversation history for this question
  1799→    const history = await pool.query(
  1800→      'SELECT role, message FROM assessment_conversations WHERE attempt_id = $1 AND question_id = $2 ORDER BY created_at',
  1801→      [attemptId, questionId]
  1802→    );
  1803→
  1804→    const convoHistory = history.rows.map(h => `${h.role}: ${h.message}`).join('\n');
  1805→
  1806→    // Save candidate's message
  1807→    await pool.query(
  1808→      'INSERT INTO assessment_conversations (attempt_id, question_id, role, message) VALUES ($1, $2, $3, $4)',
  1809→      [attemptId, questionId, 'candidate', message]
  1810→    );
  1811→
  1812→    // Limit to 3 follow-ups per question
  1813→    const aiTurns = history.rows.filter(h => h.role === 'ai').length;
  1814→    if (aiTurns >= 3) {
  1815→      return res.json({
  1816→        reply: "Thank you for your thorough response. Let's move on to the next question.",
  1817→        done: true,
  1818→        followUpCount: aiTurns
  1819→      });
  1820→    }
  1821→
  1822→    // AI generates follow-up
  1823→    const prompt = `You are conducting a skill assessment conversation. Based on the candidate's answer, ask ONE probing follow-up question to assess their depth of understanding.
  1824→
  1825→ASSESSMENT QUESTION: ${question.question_text}
  1826→${question.rubric ? 'RUBRIC: ' + question.rubric : ''}
  1827→
  1828→CONVERSATION SO FAR:
  1829→${convoHistory}
  1830→candidate: ${message}
  1831→
  1832→Rules:
  1833→- Ask ONE specific follow-up that probes deeper
  1834→- If they gave a surface-level answer, ask for specifics
  1835→- If they mentioned an interesting approach, ask them to elaborate
  1836→- If they seem to have fully answered, say so and indicate you're satisfied
  1837→- Keep it conversational and professional
  1838→
  1839→Return ONLY valid JSON:
  1840→{
  1841→  "reply": "Your follow-up question or acknowledgment",
  1842→  "satisfied": true/false,
  1843→  "depth_score": 1-10,
  1844→  "notes": "Brief assessment note"
  1845→}`;
  1846→
  1847→    const response = await chat(prompt, {
  1848→      maxTokens: 512,
  1849→      module: 'assessments', feature: 'conversational'
  1850→    });
  1851→    const parsed = safeParseJSON(response);
  1852→
  1853→    const reply = parsed?.reply || "Could you elaborate on your approach?";
  1854→    const satisfied = parsed?.satisfied || false;
  1855→
  1856→    // Save AI reply
  1857→    await pool.query(
  1858→      'INSERT INTO assessment_conversations (attempt_id, question_id, role, message, metadata) VALUES ($1, $2, $3, $4, $5)',
  1859→      [attemptId, questionId, 'ai', reply, JSON.stringify({ satisfied, depth_score: parsed?.depth_score, notes: parsed?.notes })]
  1860→    );
  1861→
  1862→    res.json({
  1863→      reply,
  1864→      done: satisfied,
  1865→      followUpCount: aiTurns + 1
  1866→    });
  1867→  } catch (error) {
  1868→    console.error('Error in conversational assessment:', error);
  1869→    res.status(500).json({ error: 'Failed to generate follow-up' });
  1870→  }
  1871→});
